import copy
import random

random.seed(42)  # ✅ makes output stable every run

TARGET_SIZE = 400

def slight_variation(p, i):
    p = copy.deepcopy(p)

    # deterministic variation using index
    factor = (i % 10 - 5) / 100  # -5% to +4%
    price = float(p["price"])
    p["price"] = f"{max(100, price * (1 + factor)):.2f}"

    # rotate locations
    locs = list(LOCS.values())
    p["location"] = locs[i % len(locs)]

    # toggle negotiable deterministically
    p["negotiable"] = (i % 2 == 0)

    # adjust quantity for new items
    if p["condition"] == "new":
        p["quantity"] = max(1, p["quantity"] + (i % 3))

    return p

# expand to exact size
expanded = []
i = 0

while len(expanded) < TARGET_SIZE:
    for base in P:
        expanded.append(slight_variation(base, i))
        i += 1
        if len(expanded) >= TARGET_SIZE:
            break

P = expanded

with open("market/seed/seed.json", "w", encoding="utf-8") as f:
    json.dump(P, f, indent=2, ensure_ascii=False)

print(f"Saved {len(P)} products")